        const DWORD remaining = static_cast<DWORD>(durationMs - elapsed);
        const DWORD waitMs = (remaining > 40) ? 40 : remaining;
        const DWORD waitRc = MsgWaitForMultipleObjects(0, nullptr, FALSE, waitMs, QS_ALLINPUT);
