            SC_STATUS_PROCESS_INFO,
            reinterpret_cast<LPBYTE>(&ssp),
            static_cast<DWORD>(sizeof(ssp)),
            &needed))
        {
            probe.state = ssp.dwCurrentState;
            probe.running = (ssp.dwCurrentState == SERVICE_RUNNING);
