    private func resetInFlightSends() {
        inFlightLock.lock()
        inFlightSends = 0
        inFlightLock.unlock()
    }

    private func currentInFlightSends() -> Int {
        inFlightLock.lock()
        let value = inFlightSends
        inFlightLock.unlock()
        return value
    }

    private func currentInFlightLimit() -> Int {
        if runtimeFPS <= 30.0 {
            return min(maxInFlightSends, 2)
        }
        if runtimeFPS <= 60.0 {
            return min(maxInFlightSends, 3)
        }
        return min(maxInFlightSends, 4)
    }

    private func tryAcquireInFlightSlot(limit: Int) -> Bool {
        inFlightLock.lock()
        defer { inFlightLock.unlock() }
        if inFlightSends >= limit { return false }
        inFlightSends += 1
        return true
    }

    private func releaseInFlightSlot() {
        inFlightLock.lock()
        if inFlightSends > 0 { inFlightSends -= 1 }
        inFlightLock.unlock()
    }

